content.problemStatement:
Public setter methods in C++ are member functions that allow **modification of private or protected class variables** from outside the class. These methods usually take a parameter and assign it to the corresponding private variable. They typically **do not return any value** (`void` is used as the return type).

**Syntax:**
```cpp
class ClassName {  
private:
    // Private variable: This stores the state of the object, and is not directly accessible outside the class
    dataType variableName;  

public:
    // Setter method to modify the private variable
    void setVariableName(dataType newValue) {  // 'newValue' is the value passed to set the private variable
        variableName = newValue;  // Assign the new value to the private variable 'variableName'
    }
};
```
---
**Example:**
```cpp
#include 
using namespace std;

class Student {
private:
    string name;  // Private variable: Stores student's name
    int age;  // Private variable: Stores student's age

public:
    // Public setter methods to update private attributes
    void setName(string studentName) {
        name = studentName;
    }

    void setAge(int studentAge) {
        age = studentAge;
    }

    // Method to display student details
    void displayInfo() {
        cout << "Student Name: " << name << ", Age: " << age << endl;
    }
};

int main() {
    Student student1;  // Creating a Student object

    student1.setName("Alexander"); // Setting name using setter methods
    student1.setAge(20); // Setting age using setter methods

    student1.displayInfo();  // Displaying updated student information

    return 0;
}
```

**Expected Output:**
```default
Student Name: Alexander, Age: 20
```

